    dict(tmdb_id=9502, title='Kung Fu Panda', year=2008, genre='Animation', director='Mark Osborne', cast=['Jack Black', 'Angelina Jolie', 'Dustin Hoffman'], avg_rating=7.3, poster_url='https://image.tmdb.org/t/p/w500/wWt4JYXTg5Wr3xBW2phBrMKgp3x.jpg', description='Chosen by prophecy but doubted by all, Po is an unlikely Dragon Warrior—a clumsy panda thrust into the world of kung fu as a deadly enemy threatens the Valley of Peace. Under reluctant guidance by Master Shifu and the Furious Five, Po must embrace who he is to unlock the power that no scroll can teach.'),
